def p(g):
    # find two non-zero colors
    colors = [c for c in set(sum(g, [])) if c != 0]
    if len(colors) != 2:
        # fallback: just pick the two most common non-zero
        from collections import Counter
        cnt = Counter(x for row in g for x in row if x)
        colors = [c for c, _ in cnt.most_common(2)]
    c1, c2 = colors
    # collect positions
    p1 = [(r, c) for r in range(10) for c in range(10) if g[r][c] == c1]
    p2 = [(r, c) for r in range(10) for c in range(10) if g[r][c] == c2]
    # compute base ranges
    def bases(ptlist):
        min_r = min(r for r, _ in ptlist)
        max_r = max(r for r, _ in ptlist)
        min_c = min(c for _, c in ptlist)
        max_c = max(c for _, c in ptlist)
        return (range(max_r - 2, min_r + 1), range(max_c - 2, min_c + 1))
    br1, bc1 = bases(p1)
    br2, bc2 = bases(p2)
    # search for valid offsets
    full = {(i, j) for i in range(3) for j in range(3)}
    for b1r in br1:
        for b1c in bc1:
            off1 = {(r - b1r, c - b1c) for r, c in p1}
            if not all(0 <= x < 3 and 0 <= y < 3 for x, y in off1):
                continue
            for b2r in br2:
                for b2c in bc2:
                    off2 = {(r - b2r, c - b2c) for r, c in p2}
                    if not all(0 <= x < 3 and 0 <= y < 3 for x, y in off2):
                        continue
                    if off1.isdisjoint(off2) and off1.union(off2) == full:
                        out = [[0]*3 for _ in range(3)]
                        for r, c in off1:
                            out[r][c] = c1
                        for r, c in off2:
                            out[r][c] = c2
                        return out
    # should never reach here
    return [[]]

